import { useState, useRef, useEffect } from "react";
import axios from "axios";

const API = "http://localhost:5000/api";

const CUISINES = ["Any", "South Indian", "North Indian", "Chinese", "Italian", "Continental"];
const MOODS = ["😊 Happy", "😢 Sad", "😤 Stressed", "😴 Tired", "🤒 Sick", "💪 Energetic"];
const DIET_TYPES = ["Any", "🥗 Veg", "🍖 Non-Veg", "🌱 Vegan"];
const SUGGESTIONS = [
  "I have tomato, onion and rice 🍅",
  "Something spicy for dinner 🌶️",
  "Light breakfast ideas 🌅",
  "I want comfort food 🥘",
  "Quick 15 min recipe ⚡",
];

const getMealTime = () => {
  const hour = new Date().getHours();
  if (hour >= 5 && hour < 11) return "Breakfast";
  if (hour >= 11 && hour < 16) return "Lunch";
  if (hour >= 16 && hour < 19) return "Snacks";
  return "Dinner";
};

export default function App() {
  const [page, setPage] = useState("login");
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [token, setToken] = useState("");
  const [userName, setUserName] = useState("");
  const [query, setQuery] = useState("");
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState("");
  const [theme, setTheme] = useState("dark");
  const [cuisine, setCuisine] = useState("Any");
  const [favourites, setFavourites] = useState([]);
  const [mood, setMood] = useState("");
  const [dietType, setDietType] = useState("Any");
  const [bmi, setBmi] = useState(null);
  const [height, setHeight] = useState("");
  const [weight, setWeight] = useState("");
  const [waterCount, setWaterCount] = useState(0);
  const [calorieLog, setCalorieLog] = useState([]);
  const [calorieInput, setCalorieInput] = useState("");
  const [mealPlan, setMealPlan] = useState("");
  const [mealPlanLoading, setMealPlanLoading] = useState(false);
  const chatEndRef = useRef(null);

  const isDark = theme === "dark";
  const colors = {
    bg: isDark ? "#0f0f1a" : "#f0f4ff",
    sidebar: isDark ? "#1a1a2e" : "#ffffff",
    chat: isDark ? "#16213e" : "#f8f9ff",
    card: isDark ? "#1e2a45" : "#ffffff",
    bubble_ai: isDark ? "#1e3a5f" : "#e8f0fe",
    bubble_user: isDark ? "#2d6a4f" : "#d4edda",
    text: isDark ? "#e0e0e0" : "#1a1a2a",
    subtext: isDark ? "#888" : "#666",
    input: isDark ? "#1a1a2e" : "#ffffff",
    border: isDark ? "#2a2a4a" : "#e0e0e0",
    accent: "#ff6b35",
    accent2: "#4cc9f0",
    purple: "#6c63ff",
    green: "#4caf50",
  };

  const styles = {
    page: {
      minHeight: "100vh",
      background: colors.bg,
      color: colors.text,
      fontFamily: "'Segoe UI', sans-serif",
      transition: "all 0.3s"
    },
    input: {
      width: "100%",
      padding: "12px 16px",
      marginBottom: "12px",
      borderRadius: "10px",
      border: `1px solid ${colors.border}`,
      background: colors.input,
      color: colors.text,
      fontSize: "15px",
      outline: "none",
      boxSizing: "border-box"
    },
    btn: {
      padding: "12px 24px",
      background: `linear-gradient(135deg, ${colors.accent}, #ff8c42)`,
      color: "white",
      border: "none",
      borderRadius: "10px",
      cursor: "pointer",
      fontSize: "15px",
      fontWeight: "600"
    },
    btnSecondary: {
      padding: "10px 20px",
      background: colors.border,
      color: colors.text,
      border: "none",
      borderRadius: "10px",
      cursor: "pointer",
      fontSize: "14px"
    },
    card: {
      background: colors.card,
      borderRadius: "16px",
      padding: "24px",
      border: `1px solid ${colors.border}`,
      boxShadow: isDark ? "0 4px 20px rgba(0,0,0,0.3)" : "0 4px 20px rgba(0,0,0,0.08)"
    },
    sidebarBtn: (active) => ({
      display: "block",
      width: "100%",
      padding: "10px 14px",
      marginBottom: "6px",
      background: active ? colors.accent : "transparent",
      color: active ? "white" : colors.text,
      border: "none",
      borderRadius: "10px",
      cursor: "pointer",
      textAlign: "left",
      fontSize: "13px",
      fontWeight: active ? "600" : "400"
    }),
  };

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const register = async () => {
    try {
      const res = await axios.post(`${API}/auth/register`, { name, email, password });
      setMessage(res.data.message);
      setPage("login");
    } catch (err) {
      setMessage(err.response?.data?.message || "Error");
    }
  };

  const login = async () => {
    try {
      const res = await axios.post(`${API}/auth/login`, { email, password });
      setToken(res.data.token);
      setUserName(res.data.user.name);
      setMessages([{
        role: "ai",
        text: `Welcome back, ${res.data.user.name}! 👋 I'm NutriAI, your personal Indian chef assistant. It's ${getMealTime()} time! Tell me what you're craving and I'll suggest the perfect dish! 🍱`,
        time: new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })
      }]);
      setPage("home");
    } catch (err) {
      setMessage(err.response?.data?.message || "Error");
    }
  };

  const getSuggestion = async (customQuery) => {
    const q = customQuery || query;
    if (!q.trim()) return;

    const contextPrompt = `
      User query: ${q}
      Current meal time: ${getMealTime()} (${new Date().getHours()}:00 hrs)
      Cuisine preference: ${cuisine !== "Any" ? cuisine : "Any cuisine"}
      Diet type: ${dietType !== "Any" ? dietType.replace(/[^\w\s]/g, '') : "No restriction"}
      User mood: ${mood || "Not specified"}

      Based on ALL the above context, suggest a perfect Indian food dish.
      Include:
      1. Dish name and why it suits the context
      2. Key ingredients (5-6 items)
      3. Quick preparation steps (3-4 steps)
      4. Approximate nutrition: Calories, Protein, Carbs, Fat
      5. One health tip related to this dish
      Keep it friendly and conversational!
    `;

    setMessages(prev => [...prev, {
      role: "user",
      text: `${mood ? mood + " • " : ""}${dietType !== "Any" ? dietType + " • " : ""}${q}`,
      time: new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })
    }]);
    setQuery("");
    setLoading(true);
    setMessages(prev => [...prev, { role: "ai", text: "typing", time: "" }]);

    try {
      const res = await axios.post(`${API}/suggest`,
        { query: contextPrompt },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setMessages(prev => [
        ...prev.filter(m => m.text !== "typing"),
        {
          role: "ai",
          text: res.data.suggestion,
          time: new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }),
        }
      ]);
    } catch {
      setMessages(prev => [
        ...prev.filter(m => m.text !== "typing"),
        { role: "ai", text: "Sorry, something went wrong! 😅", time: "" }
      ]);
    }
    setLoading(false);
  };

  const generateMealPlan = async () => {
    setMealPlanLoading(true);
    setMealPlan("");
    try {
      const res = await axios.post(`${API}/suggest`,
        {
          query: `Generate a complete healthy Indian meal plan for one full day.
          Diet preference: ${dietType !== "Any" ? dietType : "No restriction"}
          Cuisine: ${cuisine}
          BMI: ${bmi || "Not provided"}
          Mood: ${mood || "Normal"}

          Format it clearly:
          🌅 Breakfast (7:00 AM) - meal name + calories
          🍎 Mid-morning Snack (10:30 AM) - meal name + calories  
          🍽️ Lunch (1:00 PM) - meal name + calories
          ☕ Evening Snack (4:30 PM) - meal name + calories
          🌙 Dinner (8:00 PM) - meal name + calories

          Total estimated calories for the day.
          Make it practical and easy to prepare at home!`
        },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setMealPlan(res.data.suggestion);
    } catch {
      setMealPlan("Error generating meal plan. Please try again!");
    }
    setMealPlanLoading(false);
  };

  const toggleFavourite = (text) => {
    setFavourites(prev =>
      prev.includes(text) ? prev.filter(f => f !== text) : [...prev, text]
    );
  };

  const copyToClipboard = (text) => {
    navigator.clipboard.writeText(text);
    alert("Copied! 📋");
  };

  const logout = () => {
    setToken("");
    setPage("login");
    setMessages([]);
  };

  // Shared Sidebar Component
  const Sidebar = () => (
    <div style={{
      width: "240px",
      minWidth: "240px",
      background: colors.sidebar,
      borderRight: `1px solid ${colors.border}`,
      display: "flex",
      flexDirection: "column",
      padding: "20px 16px",
      overflowY: "auto"
    }}>
      {/* Logo */}
      <div style={{ textAlign: "center", marginBottom: "20px", paddingBottom: "16px", borderBottom: `1px solid ${colors.border}` }}>
        <div style={{ fontSize: "28px" }}>🍱</div>
        <h2 style={{ margin: "6px 0 2px", color: colors.accent, fontSize: "18px" }}>NutriAI</h2>
        <p style={{ margin: 0, fontSize: "11px", color: colors.subtext }}>Personal Chef Assistant</p>
      </div>

      {/* User */}
      <div style={{ background: colors.chat, borderRadius: "10px", padding: "10px 12px", marginBottom: "16px" }}>
        <p style={{ margin: 0, fontSize: "11px", color: colors.subtext }}>Logged in as</p>
        <p style={{ margin: "3px 0 0", fontWeight: "600", fontSize: "14px" }}>👤 {userName}</p>
        <p style={{ margin: "2px 0 0", fontSize: "11px", color: colors.accent }}>🍽️ {getMealTime()} time</p>
      </div>

      {/* Navigation */}
      <p style={{ fontSize: "10px", color: colors.subtext, marginBottom: "6px", textTransform: "uppercase", letterSpacing: "1px" }}>Navigation</p>
      <button style={styles.sidebarBtn(page === "home")} onClick={() => setPage("home")}>💬 AI Chat</button>
      <button style={styles.sidebarBtn(page === "dashboard")} onClick={() => setPage("dashboard")}>📊 Dashboard</button>
      <button style={styles.sidebarBtn(page === "mealplan")} onClick={() => setPage("mealplan")}>🗓️ Meal Planner</button>

      <div style={{ height: "1px", background: colors.border, margin: "12px 0" }} />

      {/* Mood */}
      <p style={{ fontSize: "10px", color: colors.subtext, marginBottom: "6px", textTransform: "uppercase", letterSpacing: "1px" }}>Your Mood</p>
      <div style={{ display: "flex", flexWrap: "wrap", gap: "4px", marginBottom: "12px" }}>
        {MOODS.map(m => (
          <button key={m} onClick={() => setMood(mood === m ? "" : m)}
            style={{ padding: "4px 8px", background: mood === m ? colors.accent : colors.chat, color: mood === m ? "white" : colors.text, border: "none", borderRadius: "6px", cursor: "pointer", fontSize: "11px" }}>
            {m}
          </button>
        ))}
      </div>

      {/* Diet */}
      <p style={{ fontSize: "10px", color: colors.subtext, marginBottom: "6px", textTransform: "uppercase", letterSpacing: "1px" }}>Diet Type</p>
      <div style={{ display: "flex", flexWrap: "wrap", gap: "4px", marginBottom: "12px" }}>
        {DIET_TYPES.map(d => (
          <button key={d} onClick={() => setDietType(d)}
            style={{ padding: "4px 8px", background: dietType === d ? colors.accent2 : colors.chat, color: dietType === d ? "white" : colors.text, border: "none", borderRadius: "6px", cursor: "pointer", fontSize: "11px" }}>
            {d}
          </button>
        ))}
      </div>

      {/* Cuisine */}
      <p style={{ fontSize: "10px", color: colors.subtext, marginBottom: "6px", textTransform: "uppercase", letterSpacing: "1px" }}>Cuisine</p>
      <div style={{ display: "flex", flexDirection: "column", gap: "4px", marginBottom: "12px" }}>
        {CUISINES.map(c => (
          <button key={c} onClick={() => setCuisine(c)}
            style={{ padding: "6px 10px", background: cuisine === c ? colors.accent : colors.chat, color: cuisine === c ? "white" : colors.text, border: "none", borderRadius: "6px", cursor: "pointer", textAlign: "left", fontSize: "12px" }}>
            {c}
          </button>
        ))}
      </div>

      {/* Bottom */}
      <div style={{ marginTop: "auto", paddingTop: "12px", borderTop: `1px solid ${colors.border}` }}>
        <button onClick={() => setTheme(isDark ? "light" : "dark")}
          style={{ ...styles.btnSecondary, width: "100%", marginBottom: "6px", fontSize: "12px" }}>
          {isDark ? "☀️ Light Mode" : "🌙 Dark Mode"}
        </button>
        <button onClick={logout}
          style={{ ...styles.btnSecondary, width: "100%", fontSize: "12px", color: "#ff4444" }}>
          🚪 Logout
        </button>
      </div>
    </div>
  );

  // AUTH PAGES
  if (page === "register") return (
    <div style={styles.page}>
      <div style={{ maxWidth: "420px", margin: "0 auto", padding: "60px 20px" }}>
        <div style={{ background: colors.sidebar, borderRadius: "20px", padding: "40px", boxShadow: "0 20px 60px rgba(0,0,0,0.3)" }}>
          <div style={{ textAlign: "center", marginBottom: "30px" }}>
            <div style={{ fontSize: "48px" }}>🍱</div>
            <h1 style={{ margin: "10px 0 5px", color: colors.accent }}>NutriAI</h1>
            <p style={{ color: colors.subtext, margin: 0 }}>Your Personal Indian Chef Assistant</p>
          </div>
          {message && <p style={{ color: "#ff4444", textAlign: "center" }}>{message}</p>}
          <input style={styles.input} placeholder="Full Name" value={name} onChange={e => setName(e.target.value)} />
          <input style={styles.input} placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} />
          <input style={styles.input} type="password" placeholder="Password" value={password} onChange={e => setPassword(e.target.value)} />
          <div style={{ display: "flex", gap: "10px" }}>
            <button style={{ ...styles.btn, flex: 1 }} onClick={register}>Create Account</button>
            <button style={{ ...styles.btnSecondary, flex: 1 }} onClick={() => setPage("login")}>Login</button>
          </div>
        </div>
      </div>
    </div>
  );

  if (page === "login") return (
    <div style={styles.page}>
      <div style={{ maxWidth: "420px", margin: "0 auto", padding: "60px 20px" }}>
        <div style={{ background: colors.sidebar, borderRadius: "20px", padding: "40px", boxShadow: "0 20px 60px rgba(0,0,0,0.3)" }}>
          <div style={{ textAlign: "center", marginBottom: "30px" }}>
            <div style={{ fontSize: "48px" }}>🍱</div>
            <h1 style={{ margin: "10px 0 5px", color: colors.accent }}>NutriAI</h1>
            <p style={{ color: colors.subtext, margin: 0 }}>Your Personal Indian Chef Assistant</p>
          </div>
          {message && <p style={{ color: "#ff4444", textAlign: "center" }}>{message}</p>}
          <input style={styles.input} placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} />
          <input style={styles.input} type="password" placeholder="Password" value={password} onChange={e => setPassword(e.target.value)} />
          <div style={{ display: "flex", gap: "10px" }}>
            <button style={{ ...styles.btn, flex: 1 }} onClick={login}>Login</button>
            <button style={{ ...styles.btnSecondary, flex: 1 }} onClick={() => setPage("register")}>Register</button>
          </div>
        </div>
      </div>
    </div>
  );

  // DASHBOARD PAGE
  if (page === "dashboard") return (
    <div style={{ ...styles.page, display: "flex", height: "100vh", overflow: "hidden" }}>
      <Sidebar />
      <div style={{ flex: 1, overflow: "auto", background: colors.chat }}>
        <div style={{ padding: "30px" }}>
          <h2 style={{ margin: "0 0 6px", fontSize: "22px" }}>📊 Dashboard</h2>
          <p style={{ color: colors.subtext, margin: "0 0 28px" }}>Welcome back, {userName}! Here's your health overview.</p>

          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "20px" }}>

            {/* BMI Calculator */}
            <div style={styles.card}>
              <h3 style={{ margin: "0 0 16px", color: colors.accent, fontSize: "16px" }}>⚖️ BMI Calculator</h3>
              <input style={{ ...styles.input, marginBottom: "10px" }} placeholder="Height (cm)" value={height} onChange={e => setHeight(e.target.value)} />
              <input style={{ ...styles.input, marginBottom: "14px" }} placeholder="Weight (kg)" value={weight} onChange={e => setWeight(e.target.value)} />
              <button style={{ ...styles.btn, width: "100%" }}
                onClick={() => {
                  const h = height / 100;
                  setBmi((weight / (h * h)).toFixed(1));
                }}>
                Calculate BMI
              </button>
              {bmi && (
                <div style={{ marginTop: "20px", textAlign: "center", padding: "16px", background: colors.chat, borderRadius: "12px" }}>
                  <div style={{ fontSize: "52px", fontWeight: "bold", color: bmi < 18.5 ? colors.accent2 : bmi < 25 ? colors.green : bmi < 30 ? "#ff9800" : "#ff4444" }}>
                    {bmi}
                  </div>
                  <p style={{ margin: "6px 0 0", color: colors.subtext, fontSize: "14px" }}>
                    {bmi < 18.5 ? "🔵 Underweight" : bmi < 25 ? "🟢 Normal Weight" : bmi < 30 ? "🟡 Overweight" : "🔴 Obese"}
                  </p>
                </div>
              )}
            </div>

            {/* Water Tracker */}
            <div style={styles.card}>
              <h3 style={{ margin: "0 0 6px", color: colors.accent2, fontSize: "16px" }}>💧 Water Intake Tracker</h3>
              <p style={{ color: colors.subtext, fontSize: "12px", margin: "0 0 16px" }}>Daily goal: 8 glasses</p>
              <div style={{ display: "flex", flexWrap: "wrap", gap: "10px", marginBottom: "16px" }}>
                {[...Array(8)].map((_, i) => (
                  <div key={i}
                    onClick={() => setWaterCount(i + 1)}
                    style={{ fontSize: "30px", cursor: "pointer", opacity: i < waterCount ? 1 : 0.25, transition: "opacity 0.2s" }}>
                    💧
                  </div>
                ))}
              </div>
              <div style={{ background: colors.chat, borderRadius: "10px", padding: "12px", marginBottom: "12px" }}>
                <p style={{ margin: 0, fontWeight: "600", color: waterCount >= 8 ? colors.green : colors.accent }}>
                  {waterCount}/8 glasses {waterCount >= 8 ? "🎉 Goal reached!" : `— ${8 - waterCount} more to go!`}
                </p>
              </div>
              <button onClick={() => setWaterCount(0)} style={{ ...styles.btnSecondary, fontSize: "12px" }}>Reset</button>
            </div>

            {/* Calorie Log */}
            <div style={styles.card}>
              <h3 style={{ margin: "0 0 16px", color: "#ff9800", fontSize: "16px" }}>🔥 Calorie Log</h3>
              <div style={{ display: "flex", gap: "8px", marginBottom: "14px" }}>
                <input
                  style={{ ...styles.input, marginBottom: 0, flex: 1 }}
                  placeholder="e.g. Idli 2 pcs — 150 kcal"
                  value={calorieInput}
                  onChange={e => setCalorieInput(e.target.value)}
                  onKeyDown={e => {
                    if (e.key === "Enter" && calorieInput) {
                      setCalorieLog(prev => [...prev, calorieInput]);
                      setCalorieInput("");
                    }
                  }}
                />
                <button
                  onClick={() => {
                    if (calorieInput) {
                      setCalorieLog(prev => [...prev, calorieInput]);
                      setCalorieInput("");
                    }
                  }}
                  style={{ ...styles.btn, padding: "10px 16px", fontSize: "13px" }}>
                  Add
                </button>
              </div>
              <div style={{ maxHeight: "200px", overflowY: "auto" }}>
                {calorieLog.length === 0 ? (
                  <p style={{ color: colors.subtext, fontSize: "13px", textAlign: "center", padding: "20px 0" }}>No meals logged yet</p>
                ) : (
                  calorieLog.map((log, i) => (
                    <div key={i} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", background: colors.chat, padding: "8px 12px", borderRadius: "8px", marginBottom: "6px", fontSize: "13px" }}>
                      <span>{log}</span>
                      <span style={{ cursor: "pointer", color: "#ff4444", fontSize: "16px", marginLeft: "8px" }}
                        onClick={() => setCalorieLog(prev => prev.filter((_, idx) => idx !== i))}>✕</span>
                    </div>
                  ))
                )}
              </div>
              {calorieLog.length > 0 && (
                <p style={{ color: colors.subtext, fontSize: "12px", marginTop: "10px" }}>{calorieLog.length} meals logged today</p>
              )}
            </div>

            {/* Stats */}
            <div style={styles.card}>
              <h3 style={{ margin: "0 0 16px", color: colors.green, fontSize: "16px" }}>📈 Today's Stats</h3>
              <div style={{ display: "flex", flexDirection: "column", gap: "10px" }}>
                {[
                  { label: "AI Queries Today", value: messages.filter(m => m.role === "user").length, color: colors.accent },
                  { label: "Favourites Saved", value: favourites.length, color: "#ff9800" },
                  { label: "Water Glasses", value: `${waterCount}/8`, color: colors.accent2 },
                  { label: "Meals Logged", value: calorieLog.length, color: colors.green },
                  { label: "Current Meal Time", value: getMealTime(), color: colors.purple },
                  { label: "BMI Status", value: bmi ? `${bmi} kg/m²` : "Not calculated", color: colors.subtext },
                ].map((stat, i) => (
                  <div key={i} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", background: colors.chat, padding: "10px 14px", borderRadius: "10px" }}>
                    <span style={{ fontSize: "13px", color: colors.subtext }}>{stat.label}</span>
                    <span style={{ fontWeight: "700", color: stat.color, fontSize: "14px" }}>{stat.value}</span>
                  </div>
                ))}
              </div>
            </div>

          </div>
        </div>
      </div>
    </div>
  );

  // MEAL PLANNER PAGE
  if (page === "mealplan") return (
    <div style={{ ...styles.page, display: "flex", height: "100vh", overflow: "hidden" }}>
      <Sidebar />
      <div style={{ flex: 1, overflow: "auto", background: colors.chat }}>
        <div style={{ padding: "30px", maxWidth: "800px" }}>
          <h2 style={{ margin: "0 0 6px", fontSize: "22px" }}>🗓️ AI Meal Planner</h2>
          <p style={{ color: colors.subtext, margin: "0 0 28px" }}>Generate a personalized meal plan based on your preferences</p>

          {/* Preferences Summary */}
          <div style={{ ...styles.card, marginBottom: "20px" }}>
            <h3 style={{ margin: "0 0 16px", fontSize: "15px" }}>Your Current Preferences</h3>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr 1fr", gap: "12px", marginBottom: "20px" }}>
              {[
                { label: "Diet", value: dietType !== "Any" ? dietType : "No restriction" },
                { label: "Cuisine", value: cuisine },
                { label: "Mood", value: mood || "Not set" },
                { label: "BMI", value: bmi ? `${bmi} kg/m²` : "Not set" },
              ].map((pref, i) => (
                <div key={i} style={{ background: colors.chat, padding: "12px", borderRadius: "10px", textAlign: "center" }}>
                  <p style={{ margin: "0 0 4px", fontSize: "11px", color: colors.subtext }}>{pref.label}</p>
                  <p style={{ margin: 0, fontWeight: "600", fontSize: "13px" }}>{pref.value}</p>
                </div>
              ))}
            </div>
            <button
              onClick={generateMealPlan}
              disabled={mealPlanLoading}
              style={{ ...styles.btn, width: "100%", fontSize: "15px", padding: "14px" }}>
              {mealPlanLoading ? "⏳ Generating your personalized meal plan..." : "🤖 Generate AI Meal Plan"}
            </button>
          </div>

          {/* Meal Plan Result */}
          {mealPlan && (
            <div style={styles.card}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "20px" }}>
                <h3 style={{ margin: 0, color: colors.accent, fontSize: "16px" }}>📋 Your Personalized Meal Plan</h3>
                <button onClick={() => copyToClipboard(mealPlan)}
                  style={{ ...styles.btnSecondary, fontSize: "12px", padding: "6px 14px" }}>
                  📋 Copy Plan
                </button>
              </div>
              <div style={{ whiteSpace: "pre-wrap", lineHeight: "2", fontSize: "14px", color: colors.text }}>
                {mealPlan}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );

  // MAIN CHAT PAGE
  return (
    <div style={{ ...styles.page, display: "flex", height: "100vh", overflow: "hidden" }}>
      <Sidebar />

      <div style={{ flex: 1, display: "flex", flexDirection: "column", background: colors.chat }}>

        {/* Header */}
        <div style={{ padding: "14px 24px", borderBottom: `1px solid ${colors.border}`, background: colors.sidebar, display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <div>
            <h3 style={{ margin: 0, fontSize: "15px" }}>🤖 NutriAI Chef</h3>
            <p style={{ margin: 0, fontSize: "11px", color: colors.green }}>
              ● Online — {cuisine} • {getMealTime()} • {dietType !== "Any" ? dietType : "All diet"}{mood ? ` • ${mood}` : ""}
            </p>
          </div>
          <div style={{ fontSize: "12px", color: colors.subtext }}>
            {messages.filter(m => m.role === "user").length} queries today
          </div>
        </div>

        {/* Messages */}
        <div style={{ flex: 1, overflow: "auto", padding: "24px" }}>
          {messages.length <= 1 && (
            <div style={{ marginBottom: "24px" }}>
              <p style={{ color: colors.subtext, fontSize: "13px", marginBottom: "10px" }}>💡 Try these:</p>
              <div style={{ display: "flex", flexWrap: "wrap", gap: "8px" }}>
                {SUGGESTIONS.map((s, i) => (
                  <button key={i} onClick={() => getSuggestion(s)}
                    style={{ padding: "8px 16px", background: colors.sidebar, color: colors.text, border: `1px solid ${colors.border}`, borderRadius: "20px", cursor: "pointer", fontSize: "13px" }}>
                    {s}
                  </button>
                ))}
              </div>
            </div>
          )}

          {messages.map((msg, i) => (
            <div key={i} style={{ display: "flex", justifyContent: msg.role === "user" ? "flex-end" : "flex-start", marginBottom: "20px" }}>
              {msg.role === "ai" && <div style={{ fontSize: "26px", marginRight: "10px", alignSelf: "flex-end" }}>🤖</div>}
              <div style={{ maxWidth: "68%" }}>
                <div style={{
                  background: msg.role === "user" ? colors.bubble_user : colors.bubble_ai,
                  padding: "14px 18px",
                  borderRadius: msg.role === "user" ? "18px 18px 4px 18px" : "18px 18px 18px 4px",
                  fontSize: "14px",
                  lineHeight: "1.7",
                  whiteSpace: "pre-wrap"
                }}>
                  {msg.text === "typing" ? (
                    <span style={{ color: colors.subtext }}>● ● ●</span>
                  ) : msg.text}
                </div>
                {msg.role === "ai" && msg.text !== "typing" && (
                  <div style={{ display: "flex", gap: "6px", marginTop: "6px" }}>
                    <button onClick={() => toggleFavourite(msg.text)}
                      style={{ padding: "3px 10px", fontSize: "11px", background: "transparent", border: `1px solid ${colors.border}`, borderRadius: "10px", cursor: "pointer", color: favourites.includes(msg.text) ? colors.accent : colors.subtext }}>
                      {favourites.includes(msg.text) ? "❤️ Saved" : "🤍 Save"}
                    </button>
                    <button onClick={() => copyToClipboard(msg.text)}
                      style={{ padding: "3px 10px", fontSize: "11px", background: "transparent", border: `1px solid ${colors.border}`, borderRadius: "10px", cursor: "pointer", color: colors.subtext }}>
                      📋 Copy
                    </button>
                  </div>
                )}
                {msg.time && <p style={{ fontSize: "10px", color: colors.subtext, margin: "4px 0 0", textAlign: msg.role === "user" ? "right" : "left" }}>{msg.time}</p>}
              </div>
              {msg.role === "user" && <div style={{ fontSize: "26px", marginLeft: "10px", alignSelf: "flex-end" }}>👤</div>}
            </div>
          ))}
          <div ref={chatEndRef} />
        </div>

        {/* Input Area */}
        <div style={{ padding: "16px 24px", borderTop: `1px solid ${colors.border}`, background: colors.sidebar }}>
          <div style={{ display: "flex", gap: "6px", marginBottom: "10px", flexWrap: "wrap" }}>
            {mood && <span style={{ padding: "3px 10px", background: colors.accent, color: "white", borderRadius: "10px", fontSize: "11px" }}>{mood}</span>}
            {dietType !== "Any" && <span style={{ padding: "3px 10px", background: colors.accent2, color: "white", borderRadius: "10px", fontSize: "11px" }}>{dietType}</span>}
            {cuisine !== "Any" && <span style={{ padding: "3px 10px", background: colors.purple, color: "white", borderRadius: "10px", fontSize: "11px" }}>{cuisine}</span>}
            <span style={{ padding: "3px 10px", background: colors.chat, color: colors.subtext, borderRadius: "10px", fontSize: "11px" }}>🍽️ {getMealTime()}</span>
          </div>
          <div style={{ display: "flex", gap: "10px", alignItems: "center" }}>
            <input
              style={{ ...styles.input, marginBottom: 0, flex: 1, borderRadius: "25px", padding: "13px 20px" }}
              placeholder={`Ask NutriAI... (${getMealTime()} • ${cuisine})`}
              value={query}
              onChange={e => setQuery(e.target.value)}
              onKeyDown={e => e.key === "Enter" && getSuggestion()}
            />
            <button onClick={() => getSuggestion()} disabled={loading}
              style={{ ...styles.btn, borderRadius: "50%", width: "48px", height: "48px", padding: 0, fontSize: "18px", flexShrink: 0 }}>
              {loading ? "⏳" : "🚀"}
            </button>
          </div>
          <p style={{ fontSize: "11px", color: colors.subtext, textAlign: "center", marginTop: "8px", margin: "8px 0 0" }}>
            Powered by Groq AI • Press Enter to send
          </p>
        </div>
      </div>
    </div>
  );
}
